struct CalibrationProfile
{
    const char *name;
    const uint16_t *dutyCycles;
};

static const CalibrationProfile calibrationProfiles[] = {
    {"VW - 120mph; Martin Springell", motorPerformance1},
    {"VW - 120mph; Forbes-Automotive", motorPerformance2},
    {"VW - 140mph; Forbes-Automotive", motorPerformance3},
    {"VW - 160mph; Forbes-Automotive", motorPerformance4},
    {"VW - 300kph; Forbes-Automotive", motorPerformance5},
    {"Ford - 120mph_1; Forbes-Automotive", motorPerformance6},
    {"Ford - 120mph_2; Forbes-Automotive", motorPerformance7},
    {"FIAT - 40-160mph; Forbes-Automotive", motorPerformance8},
    {"FIAT - 20-110mph; Forbes-Automotive", motorPerformance9},
    {"Merc - 120mph; Forbes-Automotive", motorPerformance10},
    {"Smiths - 70mph; Forbes-Automotive", motorPerformance11},
    {"Smiths - 90mph; Forbes-Automotive", motorPerformance12},
    {"Smiths - 150mph; Forbes-Automotive", motorPerformance13},
    {"Opel Manta A-72; Forbes-Automotive", motorPerformance14},
    {"FutureCal4; Forbes-Automotive", motorPerformance15},
    {"FutureCal5; Forbes-Automotive", motorPerformance16}};

static constexpr uint8_t calibrationProfileCount = sizeof(calibrationProfiles) / sizeof(calibrationProfiles[0]);

const char *getCalibrationText(uint8_t calibrationVal)
{
    if (calibrationVal == 0 || calibrationVal > calibrationProfileCount)
    {
        return calibrationProfiles[0].name;
    }
    return calibrationProfiles[calibrationVal - 1].name;
}

uint8_t getCalibrationCount()
{
    return calibrationProfileCount;
}

void updateMotorArray()
{
    if (motorPerformanceVal == 0 || motorPerformanceVal > calibrationProfileCount)
    {
        motorPerformanceVal = 1;
    }

    memcpy_P(&motorPerformance, calibrationProfiles[motorPerformanceVal - 1].dutyCycles, sizeof(motorPerformance));
    updateMotorPerformance = false;
}
